import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Header: React.FC = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const location = useLocation();

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  const isActive = (path: string) => {
    return location.pathname === path ? 'active' : '';
  };

  useEffect(() => {
    setIsMenuOpen(false);
  }, [location]);

  return (
    <header>
      <div className="container">
        <div className="logo">
          <img src="/assets/images/logo.jpg" alt="SSSALU Logo" />
        </div>
        <nav className={isMenuOpen ? 'active' : ''}>
          <ul>
            <li><Link to="/" className={isActive('/')} onClick={() => setIsMenuOpen(false)}>Home</Link></li>
            <li><Link to="/about" className={isActive('/about')} onClick={() => setIsMenuOpen(false)}>About</Link></li>
            <li><Link to="/events" className={isActive('/events')} onClick={() => setIsMenuOpen(false)}>Events</Link></li>
            <li><Link to="/projects" className={isActive('/projects')} onClick={() => setIsMenuOpen(false)}>Projects</Link></li>
            <li><Link to="/news" className={isActive('/news')} onClick={() => setIsMenuOpen(false)}>News</Link></li>
            <li><Link to="/membership" className={isActive('/membership')} onClick={() => setIsMenuOpen(false)}>Membership</Link></li>
            <li><Link to="/gallery" className={isActive('/gallery')} onClick={() => setIsMenuOpen(false)}>Gallery</Link></li>
            <li><Link to="/alumni" className={isActive('/alumni')} onClick={() => setIsMenuOpen(false)}>Alumni</Link></li>
            <li><Link to="/contact" className={isActive('/contact')} onClick={() => setIsMenuOpen(false)}>Contact</Link></li>
          </ul>
        </nav>
        <div className="menu-toggle" onClick={toggleMenu}>
          <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-bars'}`}></i>
        </div>
      </div>
    </header>
  );
};

export default Header;
